<template>
	<view>
		<u-popup :zoom="zoom" mode="center" :popup="false" :z-index="uZIndex" v-model="value" :length="width"
		 :mask-close-able="maskCloseAble" :border-radius="borderRadius" @close="popupClose" :negative-top="negativeTop">
			<view class="u-model">
				<view v-if="showTitle" class="u-model__title u-line-1" :style="[titleStyle]">{{ title }}</view>
				<view class="u-model__content">
					<view :style="[contentStyle]" v-if="$slots.default  || $slots.$default">
						<slot />
					</view>
					<view v-else class="u-model__content__message" :style="[contentStyle]">{{ content }}</view>
				</view>
				<view class="u-model__footer u-border-top" v-if="showCancelButton || showConfirmButton">
					<view v-if="showCancelButton" :hover-stay-time="100" hover-class="u-model__btn--hover" class="u-model__footer__button"
					 :style="[cancelBtnStyle]" @tap="cancel">
						{{cancelText}}
					</view>
					<view v-if="showConfirmButton || $slots['confirm-button']" :hover-stay-time="100" :hover-class="asyncClose ? 'none' : 'u-model__btn--hover'"
					 class="u-model__footer__button hairline-left" :style="[confirmBtnStyle]" @tap="confirm">
						<slot v-if="$slots['confirm-button']" name="confirm-button"></slot>
						<block v-else>
							<u-loading mode="circle" :color="confirmColor" v-if="loading"></u-loading>
							<block v-else>
								{{confirmText}}
							</block>
						</block>
					</view>
				</view>
			</view>
		</u-popup>
	</view>
</template>

<script>
	/**
	 * modal жЁЎжҖҒжЎҶ
	 * @description еј№еҮәжЁЎжҖҒжЎҶпјҢеёёз”ЁдәҺж¶ҲжҒҜжҸҗзӨәгҖҒж¶ҲжҒҜзЎ®и®ӨгҖҒеңЁеҪ“еүҚйЎөйқўеҶ…е®ҢжҲҗзү№е®ҡзҡ„дәӨдә’ж“ҚдҪң
	 * @tutorial https://www.uviewui.com/components/modal.html
	 * @property {Boolean} value жҳҜеҗҰжҳҫзӨәжЁЎжҖҒжЎҶ
	 * @property {String | Number} z-index еұӮзә§
	 * @property {String} title жЁЎжҖҒжЎҶж ҮйўҳпјҲй»ҳи®Ө"жҸҗзӨә"пјү
	 * @property {String | Number} width жЁЎжҖҒжЎҶе®ҪеәҰпјҲй»ҳи®Ө600пјү
	 * @property {String} content жЁЎжҖҒжЎҶеҶ…е®№пјҲй»ҳи®Ө"еҶ…е®№"пјү
	 * @property {Boolean} show-title жҳҜеҗҰжҳҫзӨәж ҮйўҳпјҲй»ҳи®Өtrueпјү
	 * @property {Boolean} async-close жҳҜеҗҰејӮжӯҘе…ій—ӯпјҢеҸӘеҜ№зЎ®е®ҡжҢүй’®жңүж•ҲпјҲй»ҳи®Өfalseпјү
	 * @property {Boolean} show-confirm-button жҳҜеҗҰжҳҫзӨәзЎ®и®ӨжҢүй’®пјҲй»ҳи®Өtrueпјү
	 * @property {Stringr | Number} negative-top modalеҫҖдёҠеҒҸз§»зҡ„еҖј
	 * @property {Boolean} show-cancel-button жҳҜеҗҰжҳҫзӨәеҸ–ж¶ҲжҢүй’®пјҲй»ҳи®Өfalseпјү
	 * @property {Boolean} mask-close-able жҳҜеҗҰе…Ғи®ёзӮ№еҮ»йҒ®зҪ©е…ій—ӯmodalпјҲй»ҳи®Өfalseпјү
	 * @property {String} confirm-text зЎ®и®ӨжҢүй’®зҡ„ж–Үеӯ—еҶ…е®№пјҲй»ҳи®Ө"зЎ®и®Ө"пјү
	 * @property {String} cancel-text еҸ–ж¶ҲжҢүй’®зҡ„ж–Үеӯ—еҶ…е®№пјҲй»ҳи®Ө"еҸ–ж¶Ҳ"пјү
	 * @property {String} cancel-color еҸ–ж¶ҲжҢүй’®зҡ„йўңиүІпјҲй»ҳи®Ө"#606266"пјү
	 * @property {String} confirm-color зЎ®и®ӨжҢүй’®зҡ„ж–Үеӯ—еҶ…е®№пјҲй»ҳи®Ө"#2979ff"пјү
	 * @property {String | Number} border-radius жЁЎжҖҒжЎҶеңҶи§’еҖјпјҢеҚ•дҪҚrpxпјҲй»ҳи®Ө16пјү
	 * @property {Object} title-style иҮӘе®ҡд№үж Үйўҳж ·ејҸпјҢеҜ№иұЎеҪўејҸ
	 * @property {Object} content-style иҮӘе®ҡд№үеҶ…е®№ж ·ејҸпјҢеҜ№иұЎеҪўејҸ
	 * @property {Object} cancel-style иҮӘе®ҡд№үеҸ–ж¶ҲжҢүй’®ж ·ејҸпјҢеҜ№иұЎеҪўејҸ
	 * @property {Object} confirm-style иҮӘе®ҡд№үзЎ®и®ӨжҢүй’®ж ·ејҸпјҢеҜ№иұЎеҪўејҸ
	 * @property {Boolean} zoom жҳҜеҗҰејҖеҗҜзј©ж”ҫжЁЎејҸпјҲй»ҳи®Өtrueпјү
	 * @event {Function} confirm зЎ®и®ӨжҢүй’®иў«зӮ№еҮ»
	 * @event {Function} cancel еҸ–ж¶ҲжҢүй’®иў«зӮ№еҮ»
	 * @example <u-modal :src="title" :content="content"></u-modal>
	 */
	export default {
		name: 'u-modal',
		props: {
			// жҳҜеҗҰжҳҫзӨәModal
			value: {
				type: Boolean,
				default: false
			},
			// еұӮзә§z-index
			zIndex: {
				type: [Number, String],
				default: ''
			},
			// ж Үйўҳ
			title: {
				type: [String],
				default: 'жҸҗзӨә'
			},
			// еј№зӘ—е®ҪеәҰпјҢеҸҜд»ҘжҳҜж•°еҖј(rpx)пјҢзҷҫеҲҶжҜ”пјҢautoзӯү
			width: {
				type: [Number, String],
				default: 600
			},
			// еј№зӘ—еҶ…е®№
			content: {
				type: String,
				default: 'еҶ…е®№'
			},
			// жҳҜеҗҰжҳҫзӨәж Үйўҳ
			showTitle: {
				type: Boolean,
				default: true
			},
			// жҳҜеҗҰжҳҫзӨәзЎ®и®ӨжҢүй’®
			showConfirmButton: {
				type: Boolean,
				default: true
			},
			// жҳҜеҗҰжҳҫзӨәеҸ–ж¶ҲжҢүй’®
			showCancelButton: {
				type: Boolean,
				default: false
			},
			// зЎ®и®Өж–ҮжЎҲ
			confirmText: {
				type: String,
				default: 'зЎ®и®Ө'
			},
			// еҸ–ж¶Ҳж–ҮжЎҲ
			cancelText: {
				type: String,
				default: 'еҸ–ж¶Ҳ'
			},
			// зЎ®и®ӨжҢүй’®йўңиүІ
			confirmColor: {
				type: String,
				default: '#2979ff'
			},
			// еҸ–ж¶Ҳж–Үеӯ—йўңиүІ
			cancelColor: {
				type: String,
				default: '#606266'
			},
			// еңҶи§’еҖј
			borderRadius: {
				type: [Number, String],
				default: 16
			},
			// ж Үйўҳзҡ„ж ·ејҸ
			titleStyle: {
				type: Object,
				default () {
					return {}
				}
			},
			// еҶ…е®№зҡ„ж ·ејҸ
			contentStyle: {
				type: Object,
				default () {
					return {}
				}
			},
			// еҸ–ж¶ҲжҢүй’®зҡ„ж ·ејҸ
			cancelStyle: {
				type: Object,
				default () {
					return {}
				}
			},
			// зЎ®е®ҡжҢүй’®зҡ„ж ·ејҸ
			confirmStyle: {
				type: Object,
				default () {
					return {}
				}
			},
			// жҳҜеҗҰејҖеҗҜзј©ж”ҫж•Ҳжһң
			zoom: {
				type: Boolean,
				default: true
			},
			// жҳҜеҗҰејӮжӯҘе…ій—ӯпјҢеҸӘеҜ№зЎ®е®ҡжҢүй’®жңүж•Ҳ
			asyncClose: {
				type: Boolean,
				default: false
			},
			// жҳҜеҗҰе…Ғи®ёзӮ№еҮ»йҒ®зҪ©е…ій—ӯmodal
			maskCloseAble: {
				type: Boolean,
				default: false
			},
			// з»ҷдёҖдёӘиҙҹзҡ„margin-topпјҢеҫҖдёҠеҒҸз§»пјҢйҒҝе…Қе’Ңй”®зӣҳйҮҚеҗҲзҡ„жғ…еҶө
			negativeTop: {
				type: [String, Number],
				default: 0
			}
		},
		data() {
			return {
				loading: false, // зЎ®и®ӨжҢүй’®жҳҜеҗҰжӯЈеңЁеҠ иҪҪдёӯ
			}
		},
		computed: {
			cancelBtnStyle() {
				return Object.assign({
					color: this.cancelColor
				}, this.cancelStyle);
			},
			confirmBtnStyle() {
				return Object.assign({
					color: this.confirmColor
				}, this.confirmStyle);
			},
			uZIndex() {
				return this.zIndex ? this.zIndex : this.$u.zIndex.popup;
			}
		},
		watch: {
			// еҰӮжһңжҳҜејӮжӯҘе…ій—ӯж—¶пјҢеӨ–йғЁдҝ®ж”№v-modelзҡ„еҖјдёәfalseж—¶пјҢйҮҚзҪ®еҶ…йғЁзҡ„loadingзҠ¶жҖҒ
			// йҒҝе…ҚдёӢж¬Ўжү“ејҖзҡ„ж—¶еҖҷпјҢзҠ¶жҖҒж··д№ұ
			value(n) {
				if (n === true) this.loading = false;
			}
		},
		methods: {
			confirm() {
				// ејӮжӯҘе…ій—ӯ
				if (this.asyncClose) {
					this.loading = true;
				} else {
					this.$emit('input', false);
				}
				this.$emit('confirm');
			},
			cancel() {
				this.$emit('cancel');
				this.$emit('input', false);
				// зӣ®еүҚpopupеј№зӘ—е…ій—ӯжңүдёҖдёӘе»¶ж—¶ж“ҚдҪңпјҢжӯӨеӨ„еҒҡдёҖдёӘе»¶ж—¶
				// йҒҝе…ҚзЎ®и®ӨжҢүй’®ж–Үеӯ—еҸҳжҲҗдәҶ"зЎ®е®ҡ"еӯ—ж ·пјҢmodalиҝҳжІЎж¶ҲеӨұпјҢйҖ жҲҗи§Ҷи§үдёҚеҘҪзҡ„ж•Ҳжһң
				setTimeout(() => {
					this.loading = false;
				}, 300);
			},
			// зӮ№еҮ»йҒ®зҪ©е…ій—ӯmodalпјҢи®ҫзҪ®v-modelзҡ„еҖјдёәfalseпјҢеҗҰеҲҷж— жі•з¬¬дәҢж¬Ўеј№иө·modal
			popupClose() {
				this.$emit('input', false);
			},
			// жё…йҷӨеҠ иҪҪдёӯзҡ„зҠ¶жҖҒ
			clearLoading() {
				this.loading = false;
			}
		}
	};
</script>

<style lang="scss" scoped>
	@import "../../libs/css/style.components.scss";

	.u-model {
		height: auto;
		overflow: hidden;
		font-size: 32rpx;
		background-color: #fff;

		&__btn--hover {
			background-color: rgb(230, 230, 230);
		}

		&__title {
			padding-top: 48rpx;
			font-weight: 500;
			text-align: center;
			color: $u-main-color;
		}

		&__content {
			&__message {
				padding: 48rpx;
				font-size: 30rpx;
				text-align: center;
				color: $u-content-color;
			}
		}

		&__footer {
			@include vue-flex;

			&__button {
				flex: 1;
				height: 100rpx;
				line-height: 100rpx;
				font-size: 32rpx;
				box-sizing: border-box;
				cursor: pointer;
				text-align: center;
				border-radius: 4rpx;
			}
		}
	}
</style>
